<script setup lang="ts">
import { computed, ref, watch } from 'vue'
import { useRoute } from 'vue-router'
import { Check, Copy, Database, Mail, Plus, Save, Search, ShieldCheck, UserPlus, Users } from 'lucide-vue-next'
import DefaultLayout from '@/layouts/default.vue'
import AppModal from '@/components/AppModal.vue'
import UiButton from '@/components/ui/button/UiButton.vue'
import CourseAnalyticsChart from '@/components/charts/CourseAnalyticsChart.vue'
import { useCourseStore } from '@/stores/courses'
import { useAuthStore } from '@/stores/auth'

const route=useRoute();const store=useCourseStore();const auth=useAuthStore();const section=computed(()=>String(route.params.section))
const titles={learners:['Ученики','Управляйте доступом и следите за обучением.'],analytics:['Аналитика','Данные по курсам из Supabase.'],integrations:['Интеграции','Безопасное подключение внешних приложений.'],settings:['Настройки','Профиль и рабочее пространство.']} as const
const title=computed(()=>titles[section.value as keyof typeof titles]??titles.settings)
const query=ref('');const showInvite=ref(false);const inviteName=ref('');const inviteEmail=ref('');const copied=ref(false);const saved=ref(false);const profileName=ref('')
watch(()=>auth.user,()=>{profileName.value=String(auth.user?.user_metadata?.display_name??'')},{immediate:true})
const learners=computed(()=>store.learners.filter(item=>`${item.name} ${item.email} ${item.course}`.toLowerCase().includes(query.value.toLowerCase())))
function addLearner(){if(!inviteName.value||!inviteEmail.value)return;store.learners.push({id:`local-${Date.now()}`,name:inviteName.value,email:inviteEmail.value,course:'Не назначен',progress:0,status:'Активен'});showInvite.value=false;inviteName.value='';inviteEmail.value=''}
async function saveProfile(){await auth.updateProfile(profileName.value);saved.value=true;setTimeout(()=>saved.value=false,1300)}
async function copyEndpoint(){await navigator.clipboard?.writeText(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1`);copied.value=true;setTimeout(()=>copied.value=false,1300)}
</script>
<template><DefaultLayout><div class="product-page"><div class="product-page-head"><div><span class="eyebrow">Workspace</span><h1>{{title[0]}}</h1><p>{{title[1]}}</p></div><UiButton v-if="section==='learners'" @click="showInvite=true"><UserPlus/>Добавить ученика</UiButton></div><template v-if="section==='learners'"><div class="product-toolbar"><label><Search/><input v-model="query" placeholder="Найти ученика, email или курс"/></label><span>{{learners.length}} записей</span></div><section class="product-data-table"><header><span>Ученик</span><span>Курс</span><span>Статус</span><span>Результат</span></header><article v-for="learner in learners" :key="learner.id"><div class="product-person"><span>{{learner.name.split(' ').map(part=>part[0]).join('').slice(0,2)}}</span><p><strong>{{learner.name}}</strong><small>{{learner.email}}</small></p></div><span>{{learner.course}}</span><span class="product-status">{{learner.status}}</span><span>{{learner.progress}}%</span></article><div v-if="!learners.length" class="product-empty compact"><Users/><h3>Ученики не найдены</h3><p>Измените запрос или добавьте первого ученика.</p></div></section></template><template v-else-if="section==='analytics'"><section class="product-section"><div class="product-section-head"><div><span class="eyebrow">vue-chartjs</span><h2>Прогресс по курсам</h2><p>График строится библиотекой Chart.js по актуальным данным.</p></div></div><CourseAnalyticsChart :courses="store.courses"/></section></template><template v-else-if="section==='integrations'"><section class="product-integration"><div class="integration-symbol"><Database/></div><div><span class="product-status">Подключено</span><h2>Supabase Data API</h2><p>Авторизация, Row Level Security и данные курсов работают через отдельный Supabase-проект.</p></div><UiButton variant="secondary" @click="copyEndpoint"><component :is="copied?Check:Copy"/>{{copied?'Скопировано':'Копировать endpoint'}}</UiButton><div class="integration-details"><article><ShieldCheck/><span><small>Безопасность</small><strong>RLS включён</strong></span></article><article><Database/><span><small>Проект</small><strong>{{auth.organization?.name}}</strong></span></article><article><Mail/><span><small>Аккаунт</small><strong>{{auth.user?.email}}</strong></span></article></div></section></template><template v-else><section class="product-settings-page"><article><span class="eyebrow">Personal profile</span><h2>Данные профиля</h2><p>Имя отображается в интерфейсе и сохраняется в Supabase Auth.</p></article><form @submit.prevent="saveProfile"><label>Имя<input v-model="profileName"/></label><label>Email<input :value="auth.user?.email??''" disabled/></label><div><UiButton type="submit"><Save/>Сохранить</UiButton><span v-if="saved" class="is-success"><Check/>Сохранено</span></div></form></section></template><AppModal v-if="showInvite" title="Добавить ученика" @close="showInvite=false"><form class="form" @submit.prevent="addLearner"><label>Имя<input v-model="inviteName" autofocus placeholder="Имя ученика"/></label><label>Email<input v-model="inviteEmail" type="email" placeholder="student@example.com"/></label><div class="form-actions"><UiButton variant="secondary" @click="showInvite=false">Отмена</UiButton><UiButton type="submit"><Plus/>Добавить</UiButton></div></form></AppModal></div></DefaultLayout></template>